def _quantile_edges(values: List[float], bins: int) -> List[float]:
    """Build stable quantile bin edges for numeric distribution comparison."""
    if not values:
        return [0.0, 1.0]

    sorted_values = sorted(values)
    last_index = len(sorted_values) - 1
    edges = [sorted_values[0]]

    for idx in range(1, bins):
        position = (idx * last_index) / bins
        lower = int(position)
        upper = min(lower + 1, last_index)
        fraction = position - lower
        interpolated = sorted_values[lower] + (
            (sorted_values[upper] - sorted_values[lower]) * fraction
        )
        edges.append(interpolated)

    edges.append(sorted_values[-1])

