def population_stability_index(reference_probs: List[float], current_probs: List[float]) -> float:
    """Compute PSI score between two aligned probability vectors."""
    psi_total = 0.0
    for ref_prob, cur_prob in zip(reference_probs, current_probs):
        psi_total += (cur_prob - ref_prob) * log2(cur_prob / ref_prob)
    return max(0.0, psi_total)


def kolmogorov_smirnov_statistic(reference_values: List[float], current_values: List[float]) -> float:
    """Compute KS statistic using empirical CDF distance."""
    if not reference_values or not current_values:
        return 0.0

    ref_sorted = sorted(reference_values)
    cur_sorted = sorted(current_values)
    ref_len = len(ref_sorted)
    cur_len = len(cur_sorted)

    ref_index = 0
    cur_index = 0
    max_distance = 0.0

    while ref_index < ref_len and cur_index < cur_len:
        if ref_sorted[ref_index] <= cur_sorted[cur_index]:
            pivot = ref_sorted[ref_index]
            while ref_index < ref_len and ref_sorted[ref_index] <= pivot:
                ref_index += 1
        else:
            pivot = cur_sorted[cur_index]
            while cur_index < cur_len and cur_sorted[cur_index] <= pivot:
                cur_index += 1

        ref_cdf = ref_index / ref_len
        cur_cdf = cur_index / cur_len
        max_distance = max(max_distance, abs(ref_cdf - cur_cdf))

    max_distance = max(max_distance, abs(1.0 - (cur_index / cur_len)))
    max_distance = max(max_distance, abs((ref_index / ref_len) - 1.0))
    return max_distance


def jensen_shannon_divergence(reference_probs: List[float], current_probs: List[float]) -> float:
    """Compute bounded Jensen-Shannon divergence in base-2 space."""
    midpoint = [(ref + cur) / 2.0 for ref, cur in zip(reference_probs, current_probs)]

    def _kl_divergence(p_values: List[float], q_values: List[float]) -> float:
        """Compute KL divergence with implicit smoothing from caller."""
        total = 0.0
        for p_value, q_value in zip(p_values, q_values):
            total += p_value * log2(p_value / q_value)
        return total

    jsd = 0.5 * _kl_divergence(reference_probs, midpoint) + 0.5 * _kl_divergence(
        current_probs, midpoint
    )
    return max(0.0, min(1.0, jsd))


